var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"수고하셨습니다. 스승님.","JPN":"お疲れ様でした、師匠。","ENG":"Good work. Master.","TWN":"辛苦妳了，師父。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"전투 보고서는 본사 귀환 후에 받기로 하죠.","JPN":"戦闘報告書は本社帰還後に提出して頂きますね。","ENG":"You can debrief me once we get back to corporate HQ.","TWN":"戰鬥報告會在回總公司後收取。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"확보한 로스트 쉽의 관리는 임시로 알트 소대에게 맡기도록 하겠습니다.","JPN":"確保したロストシップの管理は、まずはアルト小隊に任せようと思います。","ENG":"For the time being, I’ll task the ALT Squad to look after the Lost Ship we secured.","TWN":"已確保的失落艦船將由阿爾特小隊臨時負責管理。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어차피 실비아 양이 곧 본국에서 관리할 인원들을 데려올 테니 우리 쪽에서 신경 쓸 건 얼마 없을.......","JPN":"シルビアさんがまもなく本国の管理スタッフを連れてきますから、こちらで気にすることはあまりない……","ENG":"Besides, Sylvia will be bringing her agents from stateside to take it off our hands soon, so we won’t really need to-","TWN":"反正希爾維亞小姐很快就會把管理人員帶到本國，我們也不用太操心。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"언제까지 모른 척하고만 있을 거야, 대체!!","JPN":"いったい、いつまでしらばくれるつもりなんだ！","ENG":"How long are you going to play dumb with me?!","TWN":"妳要裝傻到什麼時候！ "},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"나유빈이 살아 있다고!","JPN":"イチノセ・カオルが生きているんだ！","ENG":"Na Yubin is alive!","TWN":"羅瑜斌還活著？！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 오랜 세월 동안, 그 녀석이 살아 있다는 소리는 한 번도 한 적이 없었잖아?!","JPN":"これまで長い間、あいつが生きているという話は一度も聞いてないぞ！？","ENG":"You never once mentioned he’s still alive after all this time!","TWN":"這麼多年以來，妳一次都沒跟我說他還活著吧？！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"대체 뭘 숨기고 있었던 거야? 그 녀석은 또 무슨 꿍꿍이고?!","JPN":"いったい何を隠していたんだ？　それに、あいつはまた何を企んでいる？","ENG":"What were you trying to hide? And what’s he up to?!","TWN":"妳到底在隱瞞什麼？那傢伙又在搞什麼鬼？！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이건 정말 말도 안 되는.....","JPN":"こんなの本当にあり得ない……","ENG":"This is ridiculous...","TWN":"這簡直是……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님도 마찬가지죠.","JPN":"師匠も同じじゃないですか。","ENG":"I could say the same about you.","TWN":"師父也一樣啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐?","JPN":"なに？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님도 그동안 나유빈에 대해서 물어본 적은 없었죠.","JPN":"師匠だってこれまで、イチノセのことは聞かなかったじゃないですか。","ENG":"You never asked about Na Yubin all these years.","TWN":"師父也從來沒有問過羅瑜斌的消息啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"단 한 번도.","JPN":"たった一度も。","ENG":"Not once.","TWN":"連一次也沒有。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그날, 한쪽 눈을 잃고 무력화된 제가 그 지옥에서 대체 어떻게 살아 나올 수 있었을까요?","JPN":"あの日、片目を失い力を失くした私が、どうやってあの地獄から生還できたと思いますか？","ENG":"How did you think I managed to make it out of that living hell? I even lost an eye that day.","TWN":"那天，失去了一隻眼睛，無力戰鬥的我，究竟是怎麼從那個地獄中活著出來的？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"방어선이 완전히 무너지고 전멸하다시피 한 상황에서 들어보지도 못한 고위 침식체에 쫓기면서까지.......","JPN":"防衛線が完全に崩れ、全滅に近い状況で、聞いたこともない高位侵食体に追われていたのに……","ENG":"Our line of defense was completely broken, and there was that high-ranking C.O. we'd never even heard about before...","TWN":"在防禦線完全崩潰、幾乎全軍覆沒的情況下，甚至還被從未聽說過的高等侵蝕體追殺……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"대체 어떻게, 극소수의 인원이나마 살아남을 수 있었는지.......","JPN":"ほんの一握りの人数ではありましたが、どうやって生き残れたのか……","ENG":"But against all odds, a handful of us managed to survive.","TWN":"即使只有極少數人活了下來，但這到底是如何做到的……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"정말 모르셨나요?","JPN":"本当にご存じないのですか？","ENG":"Have you ever wondered how that was possible?","TWN":"這些您真的不知道嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그건.......","JPN":"それは……","ENG":"Well...","TWN":"那個……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"딱히 이제 와서 스승님께 책임 추궁을 하는 건 아니에요.","JPN":"べつに、今さら師匠に責任を問うつもりはありません。","ENG":"I’m not blaming you for that after all these years.","TWN":"事到如今，我沒有要追究師父責任的意思。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그곳에서 살아남고.......","JPN":"あの地獄から生き残って……","ENG":"Ever since I made it out alive from that place...","TWN":"從那裡活下來後……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님이 다시 돌아오신 후론 거기에 대해선 다신 생각하지 않기로 했으니까요.","JPN":"師匠が復帰されてからは、あの件について二度と考えるのはよそうと決めましたので。","ENG":"And after you returned, I decided to never think about that place again.","TWN":"我就決定等師父回來後，不再追究、也不再去想這個問題了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 적어도 스승님이 나유빈에게 그런 이야기를 할 입장은 아니죠.","JPN":"ですが少なくとも師匠は、イチノセに対してそんなこと言える立場ではありません。","ENG":"But if anything, you're in no position to speak to Na Yubin like that.","TWN":"但至少，師父沒有立場對羅瑜斌說那樣的話。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 녀석이 없었으면, 우린 모두 그날 죽었을 테니까요.","JPN":"あいつがいなかったら、私たちは全員、あの日死んでいましたから。","ENG":"We'd all have died that day if it weren't for him.","TWN":"要不是他，我們那天全都死了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만.......","JPN":"だがな……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그렇다고 해도 대체 왜 그 녀석이 리플레이서 비숍인지 뭔지 하는 녀석을 납치해 간 거야?","JPN":"だとしても、一体どうしてあいつがリプレイサー・ビショップとやらをさらったりしたんだ？","ENG":"Fine. Still, that doesn't explain why he’d abduct the Replacer Bishop.","TWN":"話是這麼說，他到底為什麼要綁架那個克隆大主教？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"둘이 무슨 관계가 있길래?","JPN":"あの2人に何の関係があるんだ？","ENG":"What’s their history?","TWN":"這兩個人之間有什麼關係？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"모릅니다.","JPN":"わかりません。","ENG":"I don’t know.","TWN":"我不知道。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"절 병원에 처박아 놓은 뒤로 그 녀석이 어딜 돌아다니는지 누굴 만나는지 제게 말해 준 적은 한 번도 없으니까요.","JPN":"私を入院させた後、あいつがどこをほっつき回ってるのか、誰に会ってるのか教えてくれたことは一度もありませんでしたから。","ENG":"Nobody told me what he's been doing since that day when he shoved me into that hospital.","TWN":"自從我被送進醫院之後，就再也不知道那個傢伙在哪、和誰見面、在幹什麼了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"처음 몇 년간은 간간히 연락하기도 했지만, 그 후로는 완전히 소식이 끊어졌죠.","JPN":"最初の数年間は時々連絡をとっていましたが、その後は完全に消息が途絶えました。","ENG":"We stayed in touch somewhat for the first few years, but we lost all contact since then.","TWN":"一開始的幾年裡，我們偶爾還有一些聯絡，但後來就完全失去了消息。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그게 다야?","JPN":"それが全てか？","ENG":"That’s it?","TWN":"這就是全部了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"솔직하게 말씀드리자면.......","JPN":"正直に言うと……","ENG":"Well, if I’m being honest...","TWN":"我得誠實地對您說……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래요, 상처가 다 나을 즈음에 제안을 하나 하더군요.","JPN":"ケガが完治する頃に1つ提案をしてきたんです。","ENG":"He did make me an offer around the time I fully recovered.","TWN":"是這樣的。當我傷勢痊癒的時候，他給了我一個提議。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"자기와 함께 하지 않겠냐고.","JPN":"自分と一緒に行かないかと。","ENG":"He asked me to join him.","TWN":"問我要不要和他一起走。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"정말 바보 같군. 그런 것도 모르고 난.......","JPN":"本当に馬鹿だった。そんなことも知らずに私は……","ENG":"How foolish of me. I had no idea...","TWN":"妳真是個笨蛋呢，我根本不知道這件事……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래서? 넌 왜 따라가지 않은 거지?","JPN":"それで？　お前はなぜついて行かなかったんだ？","ENG":"So? Why didn’t you go with him?","TWN":"所以呢？妳為什麼沒有跟他一起走？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"나 같은...... 배신자보다는 생명의 은인 쪽이 더 매력적일 텐데?","JPN":"私のような……裏切り者よりは、命の恩人にもっと惹かれただろうに。","ENG":"I mean... You’d be better off with someone who saved your life, instead of a traitor like me.","TWN":"比起我這種……叛徒，救命恩人不是比較有吸引力嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"멋대가리라고는 하나도 없는 프로포즈라서요.","JPN":"ロマンの欠片もないプロポーズでしたからね。","ENG":"Let’s just say he could’ve used a bit more pizazz when he made the proposal.","TWN":"因為那就像一點情調都沒有的求婚一樣……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"예전이나 그때나, 그 녀석은 무드라는 걸 좀 배울 필요가 있습니다.","JPN":"昔もあの時もそう。あいつはロマンというものを学ぶ必要があります。","ENG":"He was never very good at setting the ambiance. Especially for tough questions.","TWN":"不管是以前還是現在，那傢伙都得學學怎麼包裝自己呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"알겠다.","JPN":"話はわかった。","ENG":"I see.","TWN":"知道了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"결국은 직접 만나서 물어볼 수밖에 없군.","JPN":"結局のところ、直接会って確かめるしかないな。","ENG":"I guess I’ll just have to ask him myself then.","TWN":"結果，我們就只能直接問他了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"진심이십니까?","JPN":"本気ですか？","ENG":"Seriously?","TWN":"您是認真的嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이건 누가 봐도 뻔한 함정입니다.","JPN":"これは誰から見ても明らかな落とし穴です。","ENG":"This is obviously a trap.","TWN":"這是誰都能看穿的陷阱。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애초에 우리의 임무는 로스트 쉽을 찾아 의뢰인에게 인계하는 겁니다.","JPN":"そもそも私たちの任務は、ロストシップを見つけて依頼者に引き継ぐこと。","ENG":"Besides, our mission was to secure and deliver the Lost Ship to the client.","TWN":"當初我們的任務是尋找失落艦船，然後移交給委託人。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"적성인물인 리플레이서 비숍을 구출할 이유 같은 건 전혀 없어요.","JPN":"敵のリプレイサー・ビショップを救出する理由なんてありません。","ENG":"We have no reason to rescue a hostile like the Replacer Bishop.","TWN":"我們根本沒有理由去救出敵對人物克隆·大主教。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니면, 스승님. 설마 또 그 아이 때문에.......","JPN":"それとも、まさかあの子のためにまた……","ENG":"Unless of course... You're doing this for that kid again...","TWN":"還是說，師父，您該不會又是為了那孩子……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아니야!","JPN":"違う！","ENG":"No!","TWN":"不是！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"대체 몇 번을 말해야겠어? 신입은 관계없다고 했잖아?","JPN":"いったい何度言えばわかるんだ？　新人は関係ないと言っただろう。","ENG":"How many times do I have to repeat myself?! I told you the rookie has nothing to do with this!","TWN":"我到底要講多少遍？我不是說了這跟新人沒有關係嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"내가 가야 하는 건.......","JPN":"私が行くのは……","ENG":"The reason I must go see him...","TWN":"我之所以會去，是因為……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"만약...... 만약 그 녀석이 옛 일로 나를 원망하고 있다면.","JPN":"もしも……あいつが昔のことで私を恨んでいるなら。","ENG":"...Is if... if he still blames me for what happened back then...","TWN":"如果……如果那傢伙因為過去的事情，對我懷恨在心的話。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......내겐 그걸 들어 줄 의무가 있기 때문이야.","JPN":"私にはそれを聞く義務があるからだ。","ENG":"...It’s my duty to hear him out.","TWN":"……我就有必要去聽他怎麼說。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};